UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Programme Structure","The programme consists of 2 compulsory courses:Educational Research Methodology and Creativityin Education.The main requirement for awarding the PhD inEducation is the completion of a substantial andoriginal independent educational research work,which should feature elements of creativity andapplications of technology. The successfulcompletion of this requirement is demonstratedthrough the production of a thesis, describing novelfindings. The thesis should be a contribution to thecurrent school of educational thought."]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'd560b4d4-f76d-4a48-875d-8b5020909482';
