UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["RESEARCH PROPOSAL","Students will systematically structure and develop their research by developing a research proposal, which would guide the student through the entire research process.","In order to enhance the rigor of their research proposal, students will also need to complete a semester of Research Methodology in addition to participating in periodic research seminars and workshops.","PROPOSAL DEFENCE","A presentation session chaired by UOW Malaysia with invited panel of examiners to ensure the candidate is able to articulate their research ideas and plans, as well as having the necessary skills to carry out research activities as proposed.","THESIS","Upon completion of their research, students will document the research project and process in a thesis. Typically, thesis for PhD should not be more than 80,000 words.","VIVA – VOCE","Upon completion of research and thesis, candidate will undergo an oral presentation, chaired by experts in the field.","RESEARCH","Upon the approval of the research proposal, under the guidance of their supervisors, student will work independently on their research projects.","Areas of Research","Economics","Finance","Management","Marketing","Business Digitalization","Accounting","Hospitality & Tourism Management"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '2783ae7e-f082-48a6-83c0-5a85ac2f88c3';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["RESEARCH PROPOSAL","Students will systematically structure and develop their research by developing a research proposal, which would guide the student through the entire research process.","PROPOSAL DEFENCE","A presentation session chaired by UOW Malaysia with invited panel of examiners to ensure the candidate is able to articulate their research ideas and plans, as well as having the necessary skills to carry out research activities as proposed.","THESIS","Upon completion of their research, students will document the research project and process in a thesis. Typically, thesis for PhD should not be more than 80,000 words.","VIVA VOLCE","Upon completion of research and thesis, candidate will undergo an oral presentation, chaired by experts in the field.","RESEARCH","Upon the approval of the research proposal, under the guidance of their supervisors, student will work independently on their research projects.","Areas of Research","Artificial Intelligence","Big Data","Machine Learning/Deep Learning","Data Visualization","Image Processing","Industry 4.0"]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'b5370984-4782-4eb3-a5eb-ba3906a2789a';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["RESEARCH PROPOSAL","Students will systematically structure and develop their research by developing a research proposal, which would guide the student through the entire research process.","To enhance the rigor of the research proposal, the students will also need to complete a semester of Research Methodology in addition to participating in periodic research seminars and workshops.","PROPOSAL DEFENCE","A presentation session chaired by UOW Malaysia with invited panel of examiners to ensure the candidate is able to articulate their research ideas and plans, as well as having the necessary skills to carry out research activities as proposed.","RESEARCH","Upon the approval of the research proposal, under the guidance of their supervisors, student will work independently on their research projects.","THESIS","Upon completion of their research, students will document the research project and process in a thesis. Typically, thesis for PhD should not be more than 80,000 words.","VIVA VOCE","Upon completion of research and thesis, candidate will undergo an oral presentation, chaired by experts in the field.","Areas of Research","Machine Learning","Deep Learning and Artificial Intelligence","Data Visualisation","Image, Video and Speech Processing","Computer Vision and Recognition","Internet of Things (IOT / Industry 4.0)","Cyber Security","Software Engineering","Technology Consultancy","Human Machine Interaction","Data Science"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '65c328fd-d013-464a-9ac3-1e01ee404d0c';
